<Variable name="index.bg.color" description="Home, Archive, Label, Search and Error Background Color" type="color" default="#2b2d33" value="#2b2d33"/>
<Variable name="single.bg.color" description="Post and Page Background Color" type="color" default="#2b2d33" value="#2b2d33"/>
</Group>

<Group description="Header">
<Variable name="header.bg.color.1" description="Start Background Gradient Color" type="color" default="#2b2d33" value="#2b2d33"/>
<Variable name="header.bg.color.2" description="End Background Gradient Color" type="color" default="#2b2d33" value="#2b2d33"/>
</Group>

<Group description="Footer">
<Variable name="footer.bg.color.1" description="Start Background Gradient Color" type="color" default="#2b2d33" value="#2b2d33"/>
<Variable name="footer.bg.color.2" description="End Background Gradient Color" type="color" default="#2b2d33" value="#2b2d33"/>
</Group>

<Variable name="body.background" description="Background" color="$(body.background.color)" type="background" default="$(color) none repeat scroll top left" value="$(color) url() repeat scroll top center"/>

<Variable name="body.text.font" description="Font" type="font" hideEditor="true" default="normal normal 1rem sans-serif" value="normal normal 1rem sans-serif"/>
<Variable name="body.background.color" description="Background Color" type="color" hideEditor="true" default="#2b2d33" value="#2b2d33"/>
<Variable name="header.background" description="h1" type="color" hideEditor="true" default="#7d99a4" value="#7d99a4"/>
<Variable name="item.action.color" description="h2" type="color" hideEditor="true" default="#fff" value="#ffffff"/>
<Variable name="item.action.font" description="h3" type="font" hideEditor="true" default="700 15px sans-serif" value="700 15px sans-serif"/>
*/

/* Global
------------------------------- */
html[dir="rtl"][lang]{direction:rtl!important}
body{background:$(index.bg.color);color:$(body.text.color);line-height:1.42857143;margin:0;min-height:100vh;font-family:'Open Sans',sans-serif;padding-top:70px}
body.homepage_view{padding-top:0}
body.single_view{background-color:$(single.bg.color)}
body.error_view{background-image:url('https://3.bp.blogspot.com/-9FmvwdH6NtA/XHNTKm-cOeI/AAAAAAAAGl4/0HFJkQHaRsA34uW44dXTclRn0uPs80RoACLcBGAs/s1600/brick-wall.png');background-repeat:repeat}
a,a:hover,a:focus{text-decoration:none;outline:none}
a,button,input,textarea,.btn,.contact-note p,.post_snippet_text,.post_share_buttons{-webkit-transition:all 0.3s ease 0s;-o-transition:all 0.3s ease 0s;transition:all 0.3s ease 0s}
a,a:focus,.uk-spinner,.uk-form-icon:hover,.uk-button-link{color:$(body.link.color)}
button{background:transparent;border:0}
.uk-totop,.uk-tab>.uk-active>a,.uk-light .uk-tab>.uk-active>a{border-color:$(body.link.color)}
.uk-tooltip,.uk-totop,.uk-open>.uk-accordion-title{background:$(body.link.color)}
li:last-child >.uk-accordion-title{border-bottom:0}
.uk-icon-button:focus,.uk-icon-button:hover,.uk-active>.uk-icon-button,.uk-icon-button:active,.uk-light .uk-icon-button:focus,.uk-light .uk-icon-button:hover,.uk-light .uk-active>.uk-icon-button,.uk-light .uk-icon-button:active,.uk-button-default:focus,.uk-button-default:hover,.uk-button-default.uk-active,.uk-button-default:active,.uk-light .uk-button-default:focus,.uk-light .uk-button-default:hover,.uk-light .uk-button-default.uk-active,.uk-light .uk-button-default:active{background-color:$(body.link.hover.color)}
.uk-button-default:focus,.uk-button-default:hover,.uk-button-default.uk-active,.uk-button-default:active,.uk-light .uk-button-default:focus,.uk-light .uk-button-default:hover,.uk-light .uk-button-default.uk-active,.uk-light .uk-button-default:active,.uk-totop:active,.uk-totop:focus,.uk-totop:hover{border-color:$(body.link.hover.color)}
a:hover,.uk-button-link:focus,.uk-button-link:hover{color:$(body.link.hover.color)}
.uk-totop:active,.uk-totop:focus,.uk-totop:hover,.uk-accordion-title:focus,.uk-accordion-title:hover{background:$(body.link.hover.color)}
.uk-slidenav,.uk-slidenav:hover,.uk-light .uk-slidenav,.uk-light .uk-slidenav:hover{color:$(keycolor)}
.uk-slidenav:not(.uk-invisible):hover{opacity:.7}
.uk-slidenav.uk-invisible{visibility:visible!important;opacity:.4}
.uk-dotnav > * > *,.uk-light .uk-dotnav > * > *{width:12px;height:12px;border:1px solid $(keycolor)}
.uk-dotnav > * >:focus,.uk-dotnav > * >:hover,.uk-dotnav > .uk-active > *,.uk-light .uk-dotnav > * >:focus,.uk-light .uk-dotnav > * >:hover,.uk-light .uk-dotnav > .uk-active > *{background:$(keycolor);border-color:transparent}
.uk-h1,.uk-h2,.uk-h3,.uk-h4,.uk-h5,.uk-h6,h1,h2,h3,h4,h5,h6{font:inherit;font-weight:500}
.uk-h1,h1{font-size:2.23125rem;line-height:1.2}
.uk-h2,h2{font-size:1.7rem;line-height:1.3}
.uk-h3,h3{font-size:1.5rem;line-height:1.4}
.uk-h4,h4{font-size:1.25rem;line-height:1.4}
.uk-h5,h5{font-size:1rem;line-height:1.4}
.uk-h6,h6{font-size:.875rem;line-height:1.4}
.item-control,.options{display:none}
.clip{border:0;clip:rect(1px,1px,1px,1px);height:1px;width:1px;overflow:hidden;padding:0;position:absolute}
.hidden{display:none!important}
.uk-offcanvas,.uk-modal,.uk-lightbox{z-index:1060}
.uk-offcanvas .uk-close{-webkit-transition:all 0.3s ease 0s;-o-transition:all 0.3s ease 0s;transition:all 0.3s ease 0s}
.uk-offcanvas .uk-close:focus{color:#fff}
.uk-light .uk-close:focus,.uk-close:hover{color:#fff}
.uk-light .uk-spinner{color:#fff}
.uk-card-hover:not(.uk-card-default):not(.uk-card-primary):not(.uk-card-secondary):hover{background:inherit}
.mark{background-color:#eee;border:1px solid #aaa;border-radius:0;cursor:default !important}
.mark.mark_empty{height:40px;width:40px;padding:0;line-height:36px;border-radius:100%!important}
*:not(pre)>code,*:not(pre)>kbd,*:not(pre)>samp{word-break:break-all}
.uk-notification-close{top:50%;transform:translateY(-50%)}
.uk-notification-close:hover{color:$(keycolor)}
.uk-notification-message{border-radius:50px;color:inherit;padding:12px 25px 12px 25px;transition:.2s ease-in-out;transition-property:box-shadow;box-shadow:0 5px 10px #00000026;font-size:85%}
.table_content{border:1px solid #eee;border-radius:4px;box-shadow:0 5px 15px rgba(0,0,0,.08)}
.table_content .table_content_title{background-image:url("data:image/svg+xml;charset=UTF-8,%3Csvg%20width%3D%2220%22%20height%3D%2220%22%20viewBox%3D%220%200%2020%2020%22%20xmlns%3D%22http://www.w3.org/2000/svg%22%20data-svg%3D%22list%22%3E%3Crect%20x%3D%226%22%20y%3D%224%22%20width%3D%2212%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%226%22%20y%3D%229%22%20width%3D%2212%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%226%22%20y%3D%2214%22%20width%3D%2212%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%222%22%20y%3D%224%22%20width%3D%222%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%222%22%20y%3D%229%22%20width%3D%222%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%222%22%20y%3D%2214%22%20width%3D%222%22%20height%3D%221%22%3E%3C/rect%3E%3C/svg%3E");background-repeat:no-repeat;background-position:$startSide 30px top 50%;padding:12px 65px;border-bottom:1px solid rgba(0,0,0,.08)}
.table_content .uk-list{counter-reset:item_items}
.table_content .uk-list a:before{display:inline-block;margin-right:8px;content:counters(item_items,". ") ".";counter-increment:item_items;color:$(body.link.color);-webkit-transition:all 0.3s ease 0s;-o-transition:all 0.3s ease 0s;transition:all 0.3s ease 0s}
.table_content .uk-list a:hover:before{color:$(body.link.hover.color)}
.table_content .uk-list .uk-list a,.table_content .uk-list .uk-list a:before{color:#555}
.table_content > .uk-list{margin:0;padding:20px 65px;counter-reset:item}
.table_content > .uk-list > li > a:before{content:counters(item,"") ".";counter-increment:item}
.responsive_iframe{position:relative;height:0;padding-bottom:56.25%}
.responsive_iframe > *{border:0;position:absolute;width:100%;height:100%;left:0}

/* .wrapper
------------------------------- */

/* header + footer
------------------------------- */
header{background-color:$(header.bg.color.1);background-image: -webkit-gradient(linear,left top,right top,from($(header.bg.color.1)),to($(header.bg.color.2)));background-image: linear-gradient(to right,$(header.bg.color.1),$(header.bg.color.2));display:flex;flex-direction:column;padding-top:60px}
.no_waves header{-webkit-box-shadow:0 5px 15px rgba(0,0,0,.08);box-shadow:0 5px 15px rgba(0,0,0,.08)}
.compact_header header{padding-top:40px}
header .google-auto-placed,footer .google-auto-placed{display:none!important;opacity:0!important;visibility:hidden!important;height:0!important;position:absolute!important;left:0!important;top:0!important;width:0!important}

/* main
------------------------------- */
main{position:relative;z-index:3}
main .full_ads_section:not(.bottom) > .widget{margin-top:50px}
main .full_ads_section.bottom > .widget{margin-bottom:50px}
main .main_content{margin-top:50px;margin-bottom:70px}

/* .filtering_labels */
.filtering_labels .select_label a{padding:0 10px}
.filtering_labels .select_label a:not(.uk-active):not(:hover):not(:active):not(:focus){border-color:#fff}
.filtering_labels .select_view a{height:40px;width:40px}
.filtering_labels .breadcrumb .uk-breadcrumb li a,.breadcrumb .uk-breadcrumb li span{text-transform:uppercase;line-height:40px;font-size:14px;font-weight:300;letter-spacing:1px}
.filtering_labels .breadcrumb .uk-breadcrumb li a{color:$(keycolor)}
.filtering_labels .breadcrumb .uk-breadcrumb li a:hover,.breadcrumb .uk-breadcrumb li span{color:#333}

/* .blog_posts + .blog_pager */
.blog_posts .post_thumbnail a{color:#fff}
.blog_posts .post_thumbnail a img{display:block;width:100%}
.blog_posts .post_title{font-size:18px;font-weight:500;line-height:28px;text-transform:uppercase}
.blog_posts .post_title a{color:#333}
.uk-light .blog_posts .post_title a{color:#fff}
.blog_posts .post_title a:hover,.blog_posts .post_title a:focus{color:$(keycolor)}
.blog_posts .post_labels a{font-size:13px;font-weight:300}
.blog_posts .post_snippet{font-size:14px;font-weight:300;line-height:24px;color:#777766;margin-bottom:30px}
.blog_posts .post_snippet p{margin:0}
.blog_posts .post_snippet_text,.blog_posts .post_snippet.open .post_share_buttons{opacity:1;visibility:visible}
.blog_posts .post_snippet.open p,.blog_posts .post_snippet .post_share_buttons{opacity:0;visibility:hidden}
.blog_posts .post_snippet.post_snippet_off{margin-bottom:0}
.blog_posts .post_snippet.post_snippet_off .post_share_buttons{top:auto;transform:translateX(-50%);bottom:20px;box-shadow:0 5px 15px rgba(0,0,0,.08);background:#fff;padding:15px}
.blog_posts .post_share_buttons span,.single_post .post_share_buttons span{background:#333;color:#fff;line-height:36px;cursor:pointer;margin:5px}
.single_post .post_share_buttons span{margin-top:0;margin-$startSide:10px;margin-bottom:10px;margin-$endSide:0}
.blog_posts .post_share_buttons span:hover,.blog_posts .post_share_buttons span:focus,.single_post .post_share_buttons span:hover,.single_post .post_share_buttons span:focus{background:$(body.link.hover.color);color:#fff;line-height:36px}
.blog_posts .post_share_buttons.small span{line-height:25px;width:25px;height:25px}
.blog_posts .post_share_buttons.small span svg{width:15px;height:15px}
.blog_posts .post_meta{font-size:11px;font-weight:300;color:#333;text-transform:uppercase;letter-spacing:.5px}
.uk-light .blog_posts .post_meta{color:#bbb}
.blog_posts .post_meta .post_share .action{cursor:pointer}
.blog_posts .post_meta .post_share .action:hover,.blog_posts .post_meta .post_share .action.uk-active{color:$(keycolor)}
.blog_posts .post_labels a:hover,.blog_posts .post_snippet_text a:hover,.blog_posts .post_body a:hover{text-decoration:underline}
.blog_posts .list_view .uk-card {padding:20px}
.blog_posts .list_view .post_content{padding:0}
.blog_pager a:not(:hover):not(:active):not(:focus){border-color:#fff}
.blog_pager a.loading,.blog_pager a.loading:hover{cursor:default;background:#fff;color:$(keycolor);padding:5px;border:0;line-height:0}
.blog_pager .numbering{margin-bottom:-15px}
.blog_pager .numbering a,.blog_pager .numbering .mark,.blog_pager .numbering .current,.blog_pager .numbering .jump{margin-bottom:15px}
.blog_pager .numbering .current{background-color:$(body.link.hover.color);color:#fff;cursor:default}
.blog_pager .numbering .jump input,.blog_pager .numbering .jump a{height:38px;border-radius:0;font-weight:400}
.blog_pager .numbering .jump input.error{box-shadow:0 5px 10px rgba(0,0,0,.15), 0 0 0 2px #ff3547}
.blog_pager .numbering .jump a{color:#333}
.blog_pager .numbering .jump a:focus,.blog_pager .numbering .jump a:hover{color:#fff}

/* .inline_banner */
.single_post .inline_banner{margin-bottom:30px}
.inline_banner_demo{background:#f9f9f9;border:1px dashed #e5e5e5;width:100%;max-width:100%;margin:0 auto;text-align:center;font-size:14px;text-transform:uppercase}
.inline_banner_demo[data-height="250"]{height:250px;line-height:250px}
.inline_banner_demo[data-height="90"]{height:90px;line-height:90px}

/* .single_post + .full_header */
.single_post .post_title,.single_post .post_header,.single_post .post_footer,.full_header .post_title,.full_header .post_header{font-weight:300;font-size:38px}
.single_post .post_header,.full_header .post_header{font-size:12px}
.single_post .post_header a,.single_post .post_footer a,.full_header .post_header a,.full_header .post_footer a{color:$(keycolor)}
.single_post .post_header a:hover,.single_post .post_footer a:hover,.full_header .post_header a:hover,.full_header .post_footer a:hover{color:#333}
.single_post .post_header .post_header_line > span,.single_post .post_footer .post_footer_line > span,.full_header .post_header .post_header_line > span,.full_header .post_footer .post_footer_line > span{display:inline-block}
.single_post .post_header .post_header_line .post_reactions iframe,.single_post .post_footer .post_footer_line .post_reactions iframe,.full_header .post_header .post_header_line .post_reactions iframe,.full_header .post_footer .post_footer_line .post_reactions iframe{height:26px}
.single_post .post_share_label,.full_header .post_share_label{float:$startSide;height:36px;line-height:36px}
.single_post .post_share_buttons{margin-bottom:-10px!important}
.single_post .post_footer{font-size:14px}
.single_post .post_author_profile{background:#f9f9f9;border:1px solid #f1f1f1;padding:20px;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.05);box-shadow:0 5px 10px rgba(0,0,0,0.05)}
.single_post .post_author_profile .post_author_profile_photo img,.single_post .post_author_profile .post_author_profile_name img{border-radius:500px;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.15);box-shadow:0 5px 10px rgba(0,0,0,0.15)}
.single_post .post_author_profile .post_author_profile_name{font-weight:500}
.single_post .post_author_profile .post_author_profile_desc{font-weight:300;color:#444;line-height:1.6}
.single_post .post_pager{position:relative}
.single_post .post_pager a{border:1px solid #f1f1f1;padding:20px;padding-$startSide:38px;display:block;text-transform:uppercase;position:relative}
.single_post .post_pager a.blog-pager-older-link{text-align:$endSide;padding:20px;padding-$endSide:38px}
.single_post .post_pager a strong{display:block;font-size:12px}
.single_post .post_pager a .text{margin-top:10px;display:block;font-size:14px;font-weight:300;color:#444}
.single_post .post_pager a .uk-icon{position:absolute;top:50%;$startSide:-18px;margin-top:-18px}
.single_post .post_pager a:hover .uk-icon{background-color:$(body.link.hover.color);color:#fff}
.single_post .post_pager a.blog-pager-older-link .uk-icon{$endSide:-18px;$startSide:auto}
.full_header{padding:50px 0;position:relative;-webkit-box-shadow:0 5px 15px rgba(0,0,0,.08);box-shadow:0 5px 15px rgba(0,0,0,.08)}
.full_header:before{content:'';position:absolute;top:0;$startSide:0;width:100%;height:100%;z-index:1;background:#fff;opacity:0.92}
.full_header .uk-container{position:relative;z-index:2}
.full_header .post_header{margin-bottom:0!important}
.has_full_header{position:relative;background-color:#fff;background-repeat:no-repeat;background-size:cover;background-position:center}
.has_full_header > svg{position:relative;z-index:2}

/* .post_body */
.single_post .post_body{line-height:1.6}
.single_post .post_body a:hover{text-decoration:underline}
.single_post .post_body a.uk-button:hover{text-decoration:none;color:#fff}
.single_post .post_body a[imageanchor][style*="margin-left"][style*="margin-right"]{margin-$startSide:0!important;margin-$endSide:0!important}
.single_post .post_body:before,.single_post .post_body:after{display:table;content:" "}
.single_post .post_body:after{clear:both}
.single_post .post_body blockquote{font-size:17px;font-weight:300;border-$startSide:5px solid $(keycolor);padding:0 20px}
.single_post .post_body a.uk-accordion-title,.single_post .post_body .uk-tab > * > a,.single_post .post_body a.uk-accordion-title:hover,.single_post .post_body .uk-tab > * > a:hover{text-decoration:none}
.single_post .post_body div.separator a[style*="margin-right"][style*="margin-left"]{margin-left:0!important;margin-right:0!important;}
html[dir="rtl"] .single_post .post_body ul{line-height:30px}
.uk-light .single_post .post_body .uk-button-default{background-color:#fff;color:#333;border:1px solid #e5e5e5}
.uk-light .single_post .post_body .uk-button-default:hover{color:#fff;background-color:#0056b3;border-color:#0056b3}
.uk-light .single_post .post_body .uk-button-primary{background-color:#1e87f0;color:#fff;border:1px solid transparent}
.uk-light .single_post .post_body .uk-button-primary:hover{background-color:#0f7ae5;color:#fff}
.uk-light .single_post .post_body .uk-button-secondary{background-color:#222;color:#fff;border:1px solid transparent}
.uk-light .single_post .post_body .uk-button-secondary:hover{background-color:#151515;color:#fff}
.post_body_banner{margin:30px auto;max-width:100%;text-align:center;overflow:hidden}

/* .post_related */
.post_related{margin:0 -15px 15px;padding:0 15px 25px;overflow:hidden;position:relative}
.post_related .uk-slider{overflow:visible}
.post_related .post_related_title{background:#f9f9f9;font-size:14px;font-weight:700;line-height:30px;letter-spacing:1px;margin:0 0 25px;padding:8px 20px;text-transform:uppercase;border:1px solid #f1f1f1;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.05);box-shadow:0 5px 10px rgba(0,0,0,0.05)}
.post_related .blog_posts{margin-bottom:20px}
.post_related .blog_posts .uk-card-default{box-shadow:0 3px 10px rgba(0,0,0,.08)}
.post_related .blog_posts .uk-card-default:hover{box-shadow:0 5px 15px rgba(0,0,0,.16)}
.post_related .blog_posts .post_title{font-size:16px;line-height:1.4;font-weight:500;text-overflow:ellipsis;overflow:hidden;white-space:nowrap}
.post_related .blog_posts .post_title a{font-size:90%}
.single_post .post_related .uk-slidenav{position: absolute;top:-65px;$endSide:10px}
.single_post .post_related .uk-slidenav[data-uk-slidenav-previous]{$endSide:44px}

/* .post_comments */
.single_post .post_comments:not(.uk-width-auto){background:#fff;border:1px solid #f1f1f1;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.05);box-shadow:0 5px 10px rgba(0,0,0,0.05)}
.single_post .post_comments .post_comments_title{background:#f9f9f9;font-size:14px;font-weight:700;line-height:30px;letter-spacing:1px;margin:0;padding:8px 20px;text-transform:uppercase}
.single_post .post_comments .post_comments_content{background:#fff;padding:30px 20px}
.single_post .post_comments .post_comments_content ol,.single_post .post_comments .post_comments_content li{list-style:none;margin:0;padding:0}
.single_post .post_comments .post_comments_content li{border-top:1px solid rgba(0,0,0,0.1);padding:30px 0}
.single_post .post_comments .post_comments_content li:first-child{border-top:0;padding-top:0}
.single_post .post_comments .post_comments_content li:last-child{border-bottom:1px solid rgba(0,0,0,0.1)}
.single_post .post_comments .post_comments_content li .avatar-image-container{margin-bottom:30px;position:relative}
.single_post .post_comments .post_comments_content li .avatar-image-container:before,.single_post .post_comments .post_comments_content li .avatar-image-container:after,.single_post .post_comments .post_comments_content li .avatar-image-container:before,.single_post .post_comments .post_comments_content li .avatar-image-container:after{content:"";display:table}
.single_post .post_comments .post_comments_content li .avatar-image-container:after,.single_post .post_comments .post_comments_content li .avatar-image-container:after{clear:both}
.single_post .post_comments .post_comments_content li .avatar-image-container > img{background:url(https://1.bp.blogspot.com/-XmT8XvocSSo/XmOp7pvCRgI/AAAAAAAAG28/K9tbDKWdh5UrbaGFeRfC674UsN0INbUYgCLcBGAsYHQ/s1600/user.png);background-repeat:repeat;background-position-x:0%;background-position-y:0%;background-size:auto auto;background-size:35px;background-repeat:no-repeat;background-position:center;border-radius:500px;float:$startSide;height:45px;width:45px;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.15);box-shadow:0 5px 10px rgba(0,0,0,0.15)}
/*.single_post .post_comments .post_comments_content ol ol li .avatar-image-container > img{height:50px;width:50px}*/
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header{font-size:14px;font-weight:300;position:absolute;top:50%;$startSide:65px;border-$startSide:1px solid #eee;padding-$startSide:20px;z-index:1;-webkit-transform:translateY(-50%);transform:translateY(-50%)}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header cite a{font-weight:500}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header a{color:currentColor;font-style:normal;text-transform:uppercase}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header a:hover{color:$(keycolor)}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header .icon.blog-author{margin-$startSide:10px}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header .icon.blog-author:after{background:$(keycolor);color:#fff;border-radius:4px;content:'Admin';font-size:11px;padding:2px 5px}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header .datetime{margin-top:4px;text-transform:lowercase;font-size:12px;display:block;color:#777}
.single_post .post_comments .post_comments_content li .comment-block{font-size:15px;padding-$startSide:85px}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-actions{font-size:13px;font-weight:300;letter-spacing:1px;$endSide:0;top:50%;text-transform:uppercase;position:absolute;z-index:2;-webkit-transform:translateY(-50%);transform:translateY(-50%)}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-actions > * + *{margin-$startSide:15px}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-actions > span a{color:red}
.single_post .post_comments .post_comments_content .comment-thread ol ol li{background:#f9f9f9;border:1px dashed $(keycolor);border-radius:4px 4px 0 0;position:relative;margin-$startSide:85px;padding:30px 20px}
.single_post .post_comments .post_comments_content .comment-thread ol ol li+li{border-top:0;border-radius:0 0 4px 4px}
.single_post .post_comments .post_comments_content .comment-thread ol ol li:last-child{border-bottom-$startSide-radius:4px;border-bottom-$endSide-radius:4px}
/*.single_post .post_comments .post_comments_content .comment-thread ol ol li:before{background:rgba(0,0,0,.1);content:'';height:1px;top:0;$startSide:20px;$endSide:20px;position:absolute;z-index:200}*/
.single_post .post_comments .post_comments_content .comment-thread ol ol li:first-child{margin-top:30px}
.single_post .post_comments .post_comments_content .comment-thread ol ol li:first-child:before{display:none}
.single_post .post_comments .post_comments_content li .comment-block .comment-content{margin-bottom:0}
.single_post .post_comments .post_comments_content li .comment-block .deleted-comment{font-style:italic;color:#999;font-size:14px}
.single_post .post_comments iframe#comment-editor{background:#fff url(https://4.bp.blogspot.com/-zxnrT9a3Ofw/XmRFpRDiP0I/AAAAAAAAG3M/tXY-lGS4Z1ktmizov2u8wR2hGrKRAgPpwCLcBGAsYHQ/s1600/loader_light.gif) no-repeat center;margin-top:30px;padding-$startSide:9px;padding-$endSide:12px;border:1px dashed #ccc;max-width:100%;box-sizing:border-box}
html[dir="rtl"] .single_post .post_comments iframe#comment-editor{padding-$startSide:10px;padding-$endSide:12px}
.single_post .post_comments .post_comments_content .loadmore{margin-top:20px}
.single_post .post_comments .post_comments_content .loadmore.loaded{max-height:0;opacity:0;overflow:hidden;margin-top:0}
.single_post .post_comments .post_comments_content .post_comments_message{background:#eee;border-radius:5px;margin-top:20px;padding:12px 20px;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.05);box-shadow:0 5px 10px rgba(0,0,0,0.05)}
.single_post .post_comments .continue{margin-top:20px}
.single_post .post_comments .continue a{line-height:20px;display:inline-block}
.single_post .post_comments ol .continue,.single_post .post_comments .comments_locked .continue,.single_post .post_comments .comment-thread .thread-count,/*.single_post .post_comments .post_comments_content .post_comments_form,*/.single_post .post_comments .post_comments_content.comments_locked li .avatar-image-container .comment-actions > a{display:none!important}
.single_post .post_comments .comments_emotions .comments_emotions_button{user-select:none}
.single_post .post_comments .comments_emotions .comments_emotions_content_wrapper{display:none}
.single_post .post_comments .comments_emotions .comments_emotions_content{background:#fbfbfb;border:1px solid #eee;border-radius:5px;margin-top:20px;padding:15px}
.single_post .post_comments .comments_emotions .comments_emotions_content .emoji_note{margin-bottom:10px;font-weight:300;font-size:14px;text-align:center}
.single_post .post_comments .comments_emotions .comments_emotions_content span{width:32px;height:32px;display:inline-block}
.single_post .post_comments .comments_emotions .comments_emotions_content input{font-family:Segoe UI Emoji;font-size:20px;font-weight:300;display:block;border:0;background:transparent;text-align:center;width:32px;height:32px}
.single_post .post_comments .post_comments_locked{line-height:20px;text-transform:uppercase;font-weight:700}
.single_post .post_comments.not_threaded iframe#comment-editor,.single_post .post_comments.not_threaded .post_comments_locked,.single_post .post_comments.not_threaded .post_comments_content .post_comments_message{margin-top:0!important}
.single_post .post_comments.not_threaded .post_comments_content .post_comments_message{margin-bottom:20px!important}
.single_post .post_comments.not_threaded .post_comments_content .post_comments_form{display:block!important}
.single_post .post_comments.post_comments_disqus,.single_post .post_comments.post_comments_fb{background-color:#ffffff;padding:30px 20px;text-align:center}
.single_post .post_comments_wrapper .uk-tab{margin-bottom:0;margin-$startSide:-20px}
.single_post .post_comments_wrapper .uk-tab:before{display:none}
.single_post .post_comments_wrapper .uk-tab li{padding-$startSide:20px}
.single_post .post_comments_wrapper .uk-tab li a{background:#fff;padding:0 30px;font-weight:bold;font-size:12px;transition:.3s ease-in-out;transition-property:color,border,background-color,box-shadow}
.single_post .post_comments_wrapper .uk-tab li.uk-active a.blogger_open,.single_post .post_comments_wrapper .uk-tab li a.blogger_open:hover,.single_post .post_comments_wrapper .uk-tab li a.blogger_open:focus{color:orange;border-color:orange}
.single_post .post_comments_wrapper .uk-tab li.uk-active a.disqus_open,.single_post .post_comments_wrapper .uk-tab li a.disqus_open:hover,.single_post .post_comments_wrapper .uk-tab li a.disqus_open:focus{color:#2e9fff;border-color:#2e9fff}
.single_post .post_comments_wrapper .uk-tab li.uk-active a.fb_open,.single_post .post_comments_wrapper .uk-tab li a.fb_open:hover,.single_post .post_comments_wrapper .uk-tab li a.fb_open:focus{color:#3b5998;border-color:#3b5998}
.single_post .post_comments_wrapper .uk-switcher > *{margin-top:0!important}

/* .tagged */
.tagged .blog_posts li{margin-bottom:15px;width:100%}
.tagged .blog_posts .post_title{margin-bottom:10px}
.tagged .blog_posts .post_thumbnail a img{width:72px;height:72px}
.tagged .more_blog_posts{margin-top:0!important;text-align:$endSide}
.tagged .more_blog_posts a{position:relative!important;$startSide:auto;transform:none}

/* error
------------------------------- */
.error .error_content h2{font-size:40px;text-transform:uppercase;color:#f95959}
.error .error_content h2 span:nth-child(2){color:$(keycolor)}
.error .error_content h2 span:last-child{font-size:18px;color:#aaa}
.error .error_search form{max-width:350px;margin:0 auto}
.error .post_related{margin-bottom:0;padding-bottom:0}
.error .post_related .uk-dotnav{display:none}
.error .featured_error{text-align:center}

/* footer
------------------------------- */
.footer_holder{padding-top:70px}

/* .topgrid */
.topgrid_section > .widget{margin-bottom:20px;padding-bottom:20px}
.topgrid_section > .widget:last-child{margin-bottom:0;padding-bottom:0}

/* .maingrid */
.copyrights{font-size:14px;text-transform:uppercase}
.social_social a{color:#fff!important}
.social_social a:hover{color:#aaa!important}

/* gadgets style
------------------------------- */

/* .Attribution */
.Attribution{text-align:center}
.Attribution div{line-height:24px}
.Attribution div svg{fill:#fff;vertical-align:bottom;cursor:pointer;height:24px;width:24px;min-width:24px}



/* .ContactForm */
.ContactForm .uk-button{position:relative}
.ContactForm .uk-button input{background:transparent;border:0;border-radius:100px;cursor:pointer;top:0;$startSide:0;bottom:0;$endSide:0;width:100%;height:100%;opacity:0;position:absolute;padding:0;margin:0;line-height:0;font-size:0}
.ContactForm p{margin:0;overflow:hidden}
.ContactForm .contact-form-message-box{text-align:center;max-width:100%;width:100%}
.ContactForm p.contact-form-error-message-with-border,.ContactForm p.contact-form-success-message-with-border{line-height:20px;padding:5px 12px;border:0;border-radius:2px;background-color:#dedede;display:block;color:rgba(0,0,0,.87);position:relative;margin-top:14px;font-size:12px;font-weight:300}
.ContactForm p.contact-form-error-message-with-border{padding-$endSide:42px}
.contact-form-error-message-with-border:before,.contact-form-error-message-with-border img{content:'';height:22px;width:23px;line-height:22px;position:absolute;top:4px;$endSide:5px;z-index:1;background:#777;border-radius:100%}
.contact-form-error-message-with-border img{opacity:0;cursor:pointer;z-index:10}
.contact-form-error-message-with-border:after{content:'+';height:22px;line-height:22px;width:22px;position:absolute;top:5px;$endSide:5px;z-index:2;color:#dedede;font-size:26px;text-align:center;-webkit-transform:rotate(-45deg);-ms-transform:rotate(-45deg);-o-transform:rotate(-45deg);transform:rotate(-45deg)}
.ContactForm p.contact-form-success-message-with-border{background:#83B641;color:#fff;border-radius:100px}

/* .PopularPosts */
.PopularPosts ul,.PopularPosts li{margin:0;padding:0;list-style:none}
.PopularPosts ul:not(.large) li{display:inline-block;line-height:1.6;margin-bottom:15px;width:100%}
.PopularPosts ul:not(.large) li:last-child{border-bottom:0;margin-bottom:0;padding-bottom:0}
.PopularPosts ul.large li{display:inline-block;width:100%}
.PopularPosts ul.large li + li{margin-top:25px}
.PopularPosts ul li:before{display:none}
.PopularPosts ul > li > a,.PopularPosts ul > li > .item-title > a{position:relative;padding-$startSide:22px}
.PopularPosts .item-content:not(.item-large) .item-thumbnail{float:$startSide;padding:0;margin:0;margin-$endSide:10px;margin-bottom:5px}
.PopularPosts .item-content:not(.item-large) .item-thumbnail a{border-radius:500px;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.15);box-shadow:0 5px 10px rgba(0,0,0,0.15)}
.PopularPosts .item-content:not(.item-large) .item-thumbnail a,.PopularPosts .item-content:not(.item-large) .item-thumbnail a img{color:#fff;display:block;height:72px;width:72px;padding:0}
.PopularPosts .item-content:not(.item-large) .item-thumbnail .youtube_thumbnail img{transform:scale(1.5)}
.PopularPosts .item-content:not(.item-large) .item-title{font-weight:400}
.PopularPosts .item-content:not(.item-large) .item-title a:hover{text-decoration:none}
.PopularPosts .item-content:not(.item-large) .item-snippet{font-size:13px;font-weight:300;color:rgba(255,255,255,.6)}

/* .BlogArchive */
.BlogArchive a:hover{text-decoration:none}
.BlogArchive ul:not(.flat),.BlogArchive ul:not(.flat) li{margin:0;padding:0;list-style:none}
.BlogArchive #ArchiveList .collapsed > ul{display:none}
.BlogArchive #ArchiveList .expanded > ul{display:block}
.BlogArchive #ArchiveList ul ul.hierarchy li,.BlogArchive #ArchiveList ul.posts li{padding-$startSide:1.3em}
.BlogArchive #ArchiveList ul{margin-top:12px}
.BlogArchive #ArchiveList > div > ul{margin-top:0}
.BlogArchive select{width:100%}



/* .FeaturedPost + .PopularPosts */
.FeaturedPost ul,.FeaturedPost li{list-style:none;margin:0;padding:0}
.FeaturedPost .item-content,.PopularPosts .item-large{margin-bottom:-10px}
.FeaturedPost .item-thumbnail,.PopularPosts .item-large .item-thumbnail{margin-bottom:15px}
.FeaturedPost .item-thumbnail a,.PopularPosts .item-large .item-thumbnail a{color:#fff}
.FeaturedPost .item-thumbnail img,.PopularPosts .item-large .item-thumbnail img{border-radius:2px;width:100%;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.15);box-shadow:0 5px 10px rgba(0,0,0,0.15);aspect-ratio:16/9}
.FeaturedPost .item-title,.FeaturedPost .item-snippet,.PopularPosts .item-large .item-title{margin-bottom:10px}
.FeaturedPost .item-snippet,.PopularPosts .item-large .item-snippet{font-size:95%}

/* .Image */
.Image img{height:auto}
.Image .caption {margin-top:10px;display:inline-block}

/* totop */
[uk-totop].hide,[data-uk-totop].hide{$endSide:-100px!important}

/* social icons */
[class*="icon_"]{color:#fff!important;transition-property: color,background-color,box-shadow,opacity}
[class*="icon_"]:hover{opacity:.8}
.icon_facebook,.icon_facebook-square{background:#3b5998!important}
.icon_github,.icon_github-alt{background:#333!important}
.icon_instagram{background:#f77737!important}
.icon_linkedin{background:#0077b5!important}
.icon_twitter{background:#1da1f2!important}
.icon_whatsapp{background:#25d366!important}
.icon_mail{background:#444!important}
.icon_telegram{background:#0088cc!important}
.icon_copy{background:#ccc!important;color:#000!important}
.icon_x_twitter,.icon_x{background:#000!important}

/* sideanv + .sidebar
------------------------------- */
.sidenav .section .widget,.sidebar .widget{border-bottom:1px solid rgba(255,255,255,.1);margin-bottom:30px;padding-bottom:30px}
.sidenav .section .widget:last-child,.sidebar .widget:last-child{border-bottom:0;margin-bottom:0;padding-bottom:0}
.sidenav .section .widget .widget_title,.sidebar .widget .widget_title{font-size:18px}
.sidenav .section .widget .widget_title:before,.sidebar .widget .widget_title:before{border-$startSide-color:$(keycolor)}

/* .sidebar
------------------------------- */
.sidebar .widget,.sidenav:not(.uk-light) .section .widget{border-bottom:1px solid rgba(0,0,0,.1)}
.sidebar .PopularPosts .item-content:not(.item-large) .item-snippet{color:inherit}

/* .cookie-choices-info
------------------------------- */
.cookie-choices-info{background:#fff!important;color:#666!important;display:none!important;font-family:inherit!important;line-height:inherit!important;text-align:center!important;padding:20px!important;box-shadow:0 5px 15px rgba(0,0,0,.08);transition:box-shadow .1s ease-in-out}
.cookie-choices-info:hover{box-shadow:0 14px 25px rgba(0,0,0,.16)}
.cookie-choices-info .cookie-choices-text{display:block!important;font-size:inherit!important;margin:0 0 20px!important;color:inherit!important;max-width:none!important;text-align:justify!important}
.cookie-choices-info .cookie-choices-buttons{margin:0 -10px!important;display:block!important;white-space:inherit!important;text-align:center!important}
.cookie-choices-info .cookie-choices-buttons a{background-color:#c4183c;color:#fff;white-space:inherit;margin:0 8px;border:none;overflow:visible;font:inherit;text-transform:none;display:inline-block;border-radius:500px;font-weight:300;padding:0 30px;vertical-align:middle;font-size:.875rem;line-height:38px;text-align:center;text-decoration:none;box-shadow:0 5px 10px rgba(0,0,0,.15);text-transform:uppercase;transition:.3s ease-in-out;transition-property:color,background-color,border-color,box-shadow}
.cookie-choices-info .cookie-choices-buttons a + a{background-color:#4f37ac}
.cookie-choices-info .cookie-choices-buttons a:hover{background-color:#a41433;color:#fff;text-decoration:none;box-shadow:0 5px 10px rgba(0,0,0,.3)}
.cookie-choices-info .cookie-choices-buttons a + a:hover{background-color:#3f2d8b}
.cookies_on #cookieChoiceInfo{display:block!important}
.cookies_on.cookies_bottom #cookieChoiceInfo{top:auto;bottom:0}
.cookies_on.cookies_bottom_left #cookieChoiceInfo{top:auto;left:20px;bottom:20px;width:450px;max-width:calc(100% - 40px)}
.cookies_on.cookies_bottom_right #cookieChoiceInfo{top:auto;left:auto;right:20px;bottom:20px;width:450px;max-width:calc(100% - 40px)}
.cookies_on.cookies_top_left #cookieChoiceInfo{top:20px;left:20px;width:450px;max-width:calc(100% - 40px)}
.cookies_on.cookies_top_right #cookieChoiceInfo{top:20px;left:auto;right:20px;width:450px;max-width:calc(100% - 40px)}

/* .light
------------------------------- */
.light .social_social a{color:$(keycolor)}

/* .dark
------------------------------- */
.dark .mark{background-color:#313131;border:1px solid #515151}
.dark .filtering_labels .select_label a:not(.uk-active):not(:hover):not(:active):not(:focus),.dark .blog_pager a:not(:hover):not(:active):not(:focus),.dark .single_post .post_pager a .uk-icon:not(:hover):not(:active):not(:focus),.dark .tagged .more_blog_posts a:not(:hover):not(:active):not(:focus){background:#454545;border-color:#454545}
.dark .single_post .post_pager a:hover .uk-icon:not(:hover):not(:active):not(:focus){background-color:$(body.link.hover.color)}
.dark .filtering_labels .select_view a{color:#fff}
.dark .filtering_labels .breadcrumb .uk-breadcrumb li a:hover,.dark .breadcrumb .uk-breadcrumb li span{color:#919191}
.dark .error .error_content h2{color:#fff}
.dark .error .error_content h2 span:last-child{color:#000}
.dark .error .error_content p{color:#ddd}
.dark .error .error_content input{background:#454545;color:#fff;border-color:#454545}
.dark .error .error_content button{color:#fff}
.dark pre{background:#666;color:#ccc}
.dark .horizontal_tabs,.dark .vertical_tabs{border-color:#444}
.dark .uk-accordion,.dark .uk-accordion-content,.dark .uk-accordion-title{border-color:#444}
.dark :not(.uk-open)> .uk-accordion-title:not(:hover):not(:focus){background:#222}
.dark .single_post .post_header a:hover,.dark .single_post .post_footer a:hover,.dark .full_header .post_header a:hover,.dark .full_header .post_footer a:hover{color:#eee}
.dark .post_related .post_related_title,.dark .single_post .post_author_profile,.dark .single_post .post_pager a{background:#414141;border-color:#4a4a4a}
.dark .single_post .post_author_profile .post_author_profile_desc,.dark .single_post .post_pager a .text{color:#ffffff80}
.dark .single_post .post_comments_wrapper .uk-tab li a{background:#454545}
.dark .single_post .post_comments:not(.uk-width-auto){background:#3a3a3a;border-color:#4a4a4a}
.dark .single_post .post_comments .post_comments_title{background:#414141}
.dark .single_post .post_comments .post_comments_content{background:#3a3a3a}
.dark .single_post .post_comments .comments_emotions .comments_emotions_content{background:#444;border-color:#333}
.dark .single_post .post_comments .post_comments_content .comment-thread ol ol li{background:#454545}
.dark .single_post .post_comments .post_comments_content li .avatar-image-container .comment-header,.dark .single_post .post_comments .post_comments_content li,.dark .single_post .post_comments .post_comments_content li:last-child{border-color:#555}
.dark .single_post .post_comments .post_comments_content li .avatar-image-container .comment-actions > span a{color:#ff4b4b}
.dark .single_post .post_comments iframe#comment-editor{background-color:#3a3a3a;background-image:url(https://4.bp.blogspot.com/-uOMleRVxU6Q/XmRFpZDF7ZI/AAAAAAAAG3I/DH7XfYdU2cghbHcgityULnOI-A9nVgiogCLcBGAsYHQ/s1600/loader_dark.gif);border-color:#555}
.dark .single_post .post_comments .post_comments_content .post_comments_message{background:#555}
.dark .single_post .post_comments.post_comments_disqus,.dark .single_post .post_comments.post_comments_fb{background:#414141}
.dark .full_header:before{background:#444}
body.dark.single_view .top_bg.has_full_header svg .g_fill_1{color:#444}
.dark .blog_pager a.loading,.dark .blog_pager a.loading:hover{background:#454545}
.dark .cookie-choices-info{background: #333!important;color:#c4c4c4!important}
.dark .no_results,.dark .no_matching_results:before{background:#222}
.dark .uk-notification-message{background:#222}
.dark .table_content{border-color:#444}
.dark .table_content .table_content_title{background-image:url("data:image/svg+xml;charset=UTF-8,%3Csvg%20width%3D%2220%22%20height%3D%2220%22%20viewBox%3D%220%200%2020%2020%22%20xmlns%3D%22http://www.w3.org/2000/svg%22%20data-svg%3D%22list%22%20fill%3D%22rgba%28255,%20255,%20255,%200.7%29%22%3E%3Crect%20x%3D%226%22%20y%3D%224%22%20width%3D%2212%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%226%22%20y%3D%229%22%20width%3D%2212%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%226%22%20y%3D%2214%22%20width%3D%2212%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%222%22%20y%3D%224%22%20width%3D%222%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%222%22%20y%3D%229%22%20width%3D%222%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%222%22%20y%3D%2214%22%20width%3D%222%22%20height%3D%221%22%3E%3C/rect%3E%3C/svg%3E");border-color:#444}
