/* responsive
------------------------------- */
@media (max-width:1199px) and (min-width:992px){
.filtering_labels .mark:not(.mark_empty){padding:0 20px}
}
@media (min-width:992px){
.uk-offcanvas-container,.uk-offcanvas-page{overflow:auto !important}
.breadcrumb{margin-bottom:20px}
}
@media (max-width:991px){
.filtering_labels .uk-grid .uk-icon{line-height:40px}
.topgrid_section > .widget:last-child{margin-bottom:20px;padding-bottom:20px}
.sidebar{margin-top:80px}
}
@media (max-width:991px) and (min-width:768px){
main .main_content{margin-top:40px}
.filtering_labels{margin-bottom:40px!important}
.filtering_labels .select_view{margin-bottom:0!important}
.filtering_labels .uk-grid select{min-width:150px;max-width:250px}
}
@media (max-width:767px){
main .main_content{margin-top:25px}
.filtering_labels{margin-bottom:0!important}
.filtering_labels .select_label,.filtering_labels .select_view,.breadcrumb{margin-bottom:25px}
.filtering_labels .uk-grid select{width:100%}
.full_header{padding:40px 0}
.maingrid{text-align:center}
.maingrid .copyrights{margin-bottom:30px}
.maingrid .social .social_social{align-content:center;justify-content:center}
.single_post .post_author_profile .post_author_profile_name{margin-bottom:20px!important}
.single_post .post_author_profile .post_author_profile_name img{width:30px;height:30px}
.single_post .post_comments .post_comments_content li .comment-block{padding-$startSide:0}
.single_post .post_comments .post_comments_content .comment-thread ol ol li{margin-$startSide:0}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header,.single_post .post_comments .post_comments_content li .avatar-image-container .comment-actions{float:$startSide;position:relative;top:0;$startSide:0;-webkit-transform:none;transform:none}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header{margin-$startSide:20px;display:block}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-actions{width:100%;margin-top:20px;text-align:$endSide}
.error .error_content h2 span:first-child{display:block;width:100%}
.error .error_content h2 span:nth-child(2){margin-$startSide:0!important}
}
@media (max-width:575px){
.single_post .post_pager a{padding-$startSide:46px}
.single_post .post_pager a.blog-pager-older-link{padding-$endSide:46px}
.single_post .post_pager a .uk-icon{$startSide:-10px}
.single_post .post_pager a.blog-pager-older-link .uk-icon{$endSide:-10px}
.error .error_content h2 span:first-child{font-size:28px}
html[dir="rtl"] .uk-tooltip{max-width:100%;left:auto!important;right:35px}
}



