body.script:
//
(function(){
  /* Sticky navigation */
  const nav = document.getElementById('main-nav');
  const logo = document.getElementById('header-logo');
  const stickyClasses = [
    'bg-white/75',
    'backdrop-blur-[14px]',
    'shadow-[0_12px_34px_rgba(0,0,0,0.08)]',
    'dark:bg-semidark/75',
    'dark:shadow-[0_12px_34px_rgba(0,0,0,0.24)]',
    '!py-4'
  ];
  const stickyLogoClasses = [
    '!w-[112px]',
    'lg:!w-[138px]',
    'xl:!w-[148px]'
  ];

  const syncStickyState = () => {
    if (!nav) return;
    const isSticky = window.scrollY >= 100;
    stickyClasses.forEach((className) => {
      nav.classList.toggle(className, isSticky);
    });
    if (logo) {
      stickyLogoClasses.forEach((className) => {
        logo.classList.toggle(className, isSticky);
      });
    }
  };

  syncStickyState();
  window.addEventListener('scroll', syncStickyState);

  const revealTheme = () => {
    document.documentElement.classList.remove('theme-loading');
  };

  if (document.readyState === 'complete') {
    requestAnimationFrame(revealTheme);
  } else {
    window.addEventListener('load', revealTheme, { once: true });
    setTimeout(revealTheme, 3200);
  }

  /* Theme Toggle with Spin Animation */
  const themeBtn = document.getElementById('dizme-theme-btn');
  const themeBtnMobile = document.getElementById('dizme-theme-btn-mobile');

  const triggerSpin = (btn) => {
    if (!btn) return;
    const svgs = btn.querySelectorAll('svg');
    svgs.forEach((svg) => {
      if (svg.clientWidth > 0 || svg.clientHeight > 0) {
        svg.classList.remove('animate-theme-spin');
        void svg.offsetWidth; // trigger reflow
        svg.classList.add('animate-theme-spin');
        svg.addEventListener('animationend', () => {
          svg.classList.remove('animate-theme-spin');
        }, { once: true });
      }
    });
  };

  const applyTheme = (isDark, spinBtn) => {
    document.documentElement.classList.toggle('dark', isDark);
    document.body.classList.toggle('dark', isDark);
    document.body.classList.toggle('light', !isDark);
    const wrapper = document.querySelector('.wrapper');
    if (wrapper) {
      wrapper.classList.toggle('uk-light', isDark);
    }
    localStorage.setItem('theme', isDark ? 'dark' : 'light');
    if (spinBtn) {
      triggerSpin(spinBtn);
    }
  };

  if (themeBtn) {
    themeBtn.addEventListener('click', () => {
      const isDark = !document.documentElement.classList.contains('dark');
      applyTheme(isDark, themeBtn);
    });
  }
  if (themeBtnMobile) {
    themeBtnMobile.addEventListener('click', () => {
      const isDark = !document.documentElement.classList.contains('dark');
      applyTheme(isDark, themeBtnMobile);
    });
  }

  /* Mobile menu */
  const mobileBtn = document.getElementById('dizme-mobile-btn');
  const mobileMenu = document.getElementById('dizme-mobile-menu');
  const navLinks = Array.from(document.querySelectorAll('[data-nav-link]'));

  if (mobileBtn && mobileMenu) {
    mobileBtn.addEventListener('click', () => {
      mobileMenu.classList.toggle('hidden');
    });
  }

  navLinks.forEach((link) => {
    link.addEventListener('click', () => {
      if (mobileMenu) {
        mobileMenu.classList.add('hidden');
      }
    });
  });

  /* Typing animation classes matching Home.astro */
  class Typer {
    constructor(element) {
      this.element = element;
      const delim = element.dataset.delim || ",";
      const words = element.dataset.words || "";
      this.words = words.split(delim).filter((v) => v);
      this.delay = parseInt(element.dataset.delay || "200");
      this.loop = element.dataset.loop || "true";
      if (this.loop === "false") { this.loop = 1; }
      this.deleteDelay = parseInt(element.dataset.deletedelay || element.dataset.deleteDelay || "800");

      this.progress = { word: 0, char: 0, building: true, looped: 0 };
      this.typing = true;

      const colors = element.dataset.colors || "black";
      this.colors = colors.split(",");
      this.element.style.color = this.colors[0];
      this.colorIndex = 0;

      this.doTyping();
    }

    doTyping() {
      const e = this.element;
      const p = this.progress;
      const w = p.word;
      const c = p.char;

      if (!this.words[w]) return;

      const currentDisplay = [...this.words[w]].slice(0, c).join("");
      let atWordEnd = false;

      if (this.cursor) {
        this.cursor.element.style.opacity = "1";
        this.cursor.on = true;
        clearInterval(this.cursor.interval);
        this.cursor.interval = setInterval(() => this.cursor.updateBlinkState(), 400);
      }

      e.innerHTML = currentDisplay;

      if (p.building) {
        atWordEnd = p.char === this.words[w].length;
        if (atWordEnd) {
          p.building = false;
        } else {
          p.char += 1;
        }
      } else {
        if (p.char === 0) {
          p.building = true;
          p.word = (p.word + 1) % this.words.length;
          this.colorIndex = (this.colorIndex + 1) % this.colors.length;
          this.element.style.color = this.colors[this.colorIndex];
        } else {
          p.char -= 1;
        }
      }

      if (p.word === this.words.length - 1) {
        p.looped += 1;
      }

      if (!p.building && (typeof this.loop === 'number' ? this.loop : parseInt(this.loop) || Infinity) <= p.looped) {
        this.typing = false;
      }

      setTimeout(() => {
        if (this.typing) { this.doTyping(); }
      }, atWordEnd ? this.deleteDelay : this.delay);
    }
  }

  class Cursor {
    constructor(element) {
      this.element = element;
      this.cursorDisplay = element.dataset.cursordisplay || element.dataset.cursorDisplay || "|";
      element.innerHTML = this.cursorDisplay;
      this.on = true;
      element.style.transition = "all 0.1s";
      this.interval = setInterval(() => this.updateBlinkState(), 400);
    }

    updateBlinkState() {
      if (this.on) {
        this.element.style.opacity = "0";
        this.on = false;
      } else {
        this.element.style.opacity = "1";
        this.on = true;
      }
    }
  }

  const initTyper = () => {
    const typers = {};
    const typerElements = document.getElementsByClassName("typer");
    for (let e of typerElements) {
      typers[e.id] = new Typer(e);
    }
    const cursorElements = document.getElementsByClassName("cursor");
    for (let e of cursorElements) {
      const ownerId = e.dataset.owner;
      if (ownerId && typers[ownerId]) {
        const t = new Cursor(e);
        t.owner = typers[ownerId];
        typers[ownerId].cursor = t;
      }
    }
  };

  initTyper();
})();
