        document.addEventListener('DOMContentLoaded', () => {
          const bar = document.getElementById('progressbar');
          const ring = document.getElementById('progressbar-ring');
          const orbit = document.getElementById('progressbar-orbit');
          const totop = document.getElementById('scroll-top');
          const ringLength = 175.93;

          if (bar && ring && orbit) {
            const syncProgressbar = () => {
              const scroll = window.scrollY;
              const docHeight = document.documentElement.scrollHeight || document.body.scrollHeight;
              const winHeight = window.innerHeight;
              const travel = Math.max(docHeight - winHeight, 1);
              const pct = Math.min(Math.max((scroll / travel) * 100, 0), 100);
              ring.style.strokeDashoffset = String(ringLength - ((ringLength * pct) / 100));
              orbit.style.transform = 'rotate(' + ((pct / 100) * 360) + 'deg)';

              if (scroll >= 100) {
                bar.classList.remove('translate-x-6', 'opacity-0', 'pointer-events-none');
                bar.classList.add('translate-x-0', 'opacity-100');
              } else {
                bar.classList.remove('translate-x-0', 'opacity-100');
                bar.classList.add('translate-x-6', 'opacity-0', 'pointer-events-none');
              }
            };

            syncProgressbar();
            window.addEventListener('scroll', syncProgressbar, { passive: true });
          }

          if (totop) {
            totop.addEventListener('click', (e) => {
              e.preventDefault();
              window.scrollTo({ top: 0, behavior: 'smooth' });
            });
          }
        });
